<?php
session_start(); $conn=new mysqli('localhost','root','','agroconnect'); $conn->set_charset('utf8mb4'); require_once 'agro_helper.php'; if(!isset($_SESSION['rol'])){header('Location: login.php');exit();}
$rol=$_SESSION['rol']; $eid=intval($_SESSION['empresa_id']??0); $volver=agro_volver_panel(); $sinTabla=!agro_tabla_existe($conn,'recursos'); $mensaje=''; $error='';
if(!$sinTabla && isset($_POST['guardar'])){ $empresa_id=($rol==='superadmin')?intval($_POST['empresa_id']??0):$eid; $nombre=trim($_POST['nombre']??''); $tipo=$_POST['tipo']??'maquinaria'; $cantidad=floatval($_POST['cantidad']??0); $unidad=trim($_POST['unidad']??''); $estado=$_POST['estado']??'disponible'; $notas=trim($_POST['notas']??''); if($empresa_id<=0||$nombre===''){$error='Indica empresa y nombre.';} else {$st=$conn->prepare('INSERT INTO recursos (empresa_id,nombre,tipo,cantidad,unidad,estado,notas,fecha_creacion) VALUES (?,?,?,?,?,?,?,NOW())');$st->bind_param('issdsss',$empresa_id,$nombre,$tipo,$cantidad,$unidad,$estado,$notas);$mensaje=$st->execute()?'Recurso guardado correctamente.':'No se pudo guardar el recurso.';}}
if(!$sinTabla){$empresas=agro_empresas_visibles($conn); if($rol==='superadmin'){$recursos=$conn->query("SELECT r.*, e.nombre AS empresa FROM recursos r LEFT JOIN empresas e ON r.empresa_id=e.id ORDER BY r.id DESC");}else{$st=$conn->prepare("SELECT r.*, e.nombre AS empresa FROM recursos r LEFT JOIN empresas e ON r.empresa_id=e.id WHERE r.empresa_id=? ORDER BY r.id DESC");$st->bind_param('i',$eid);$st->execute();$recursos=$st->get_result();}}
?>
<!DOCTYPE html><html lang="es"><head><meta charset="UTF-8"><title>Recursos - AgroConnect</title><link href="https://cdn.jsdelivr.net/npm/bootstrap@5.3.2/dist/css/bootstrap.min.css" rel="stylesheet"><link rel="stylesheet" href="style.css"></head><body class="admin-body"><?php include __DIR__ . '/includes/topbar.php'; ?><div class="admin-container"><div class="dashboard-hero"><div><span class="eyebrow">Recursos</span><h1>Inventario agrícola</h1><p>Consulta maquinaria, herramientas, insumos, agua y personal disponible desde una única sección.</p></div></div><?php if($sinTabla){?><div class="alert alert-warning">Importa <strong>actualizacion_superadmin.sql</strong> para activar recursos.</div><?php } else { if($mensaje){?><div class="alert alert-success"><?php echo htmlspecialchars($mensaje);?></div><?php } if($error){?><div class="alert alert-danger"><?php echo htmlspecialchars($error);?></div><?php }?><div class="admin-card mb-4"><h3>Nuevo recurso</h3><form method="POST" class="row g-3 mt-1"><?php if($rol==='superadmin'){?><div class="col-md-4"><label class="form-label">Empresa</label><select name="empresa_id" class="form-select"><option value="">Seleccionar...</option><?php while($e=$empresas->fetch_assoc()){?><option value="<?php echo $e['id'];?>"><?php echo htmlspecialchars($e['nombre']);?></option><?php }?></select></div><?php }?><div class="col-md-4"><label class="form-label">Nombre</label><input name="nombre" class="form-control" required></div><div class="col-md-4"><label class="form-label">Tipo</label><select name="tipo" class="form-select"><option value="maquinaria">Maquinaria</option><option value="herramienta">Herramienta</option><option value="insumo">Insumo</option><option value="agua">Agua</option><option value="personal">Personal</option></select></div><div class="col-md-3"><label class="form-label">Cantidad</label><input type="number" step="0.01" name="cantidad" class="form-control"></div><div class="col-md-3"><label class="form-label">Unidad</label><input name="unidad" class="form-control" placeholder="kg, l, uds..."></div><div class="col-md-3"><label class="form-label">Estado</label><select name="estado" class="form-select"><option value="disponible">Disponible</option><option value="en_uso">En uso</option><option value="mantenimiento">Mantenimiento</option><option value="agotado">Agotado</option></select></div><div class="col-md-12"><label class="form-label">Notas</label><textarea name="notas" class="form-control" rows="2"></textarea></div><div class="col-12"><button name="guardar" class="btn btn-success">Guardar recurso</button></div></form></div><div class="admin-card"><h3>Recursos registrados</h3><div class="table-responsive"><table class="table"><thead><tr><th>Nombre</th><th>Empresa</th><th>Tipo</th><th>Cantidad</th><th>Estado</th><th>Notas</th><?php if(in_array($rol,['superadmin','jefe'])){ ?><th>Acciones</th><?php } ?></tr></thead><tbody><?php while($r=$recursos->fetch_assoc()){?><tr><td><strong><?php echo htmlspecialchars($r['nombre']);?></strong></td><td><?php echo htmlspecialchars($r['empresa']??'');?></td><td><?php echo htmlspecialchars($r['tipo']);?></td><td><?php echo htmlspecialchars($r['cantidad'].' '.$r['unidad']);?></td><td><span class="badge bg-success"><?php echo htmlspecialchars($r['estado']);?></span></td><td><?php echo htmlspecialchars($r['notas']);?></td><?php if(in_array($rol,['superadmin','jefe'])){ ?><td><?php echo agro_crud_botones('recursos', $r['id'], 'recursos.php'); ?></td><?php } ?></tr><?php }?></tbody></table></div></div><?php }?></div><?php include __DIR__ . '/includes/footer.php'; ?>
</body></html>
